INSERT INTO standards (id, name, product_type, steps, created_at, meta) VALUES (1, 'Banc sur mesure', 'banc', '[{"phase":"debitage","tools":["scie","défonceuse"],"description":"Débitage planches","instructions":"Couper selon plan","estimated_minutes":120},{"phase":"usinage","tools":["CNC"],"description":"Usinage CNC","instructions":"Programmes CNC banc","estimated_minutes":180},{"phase":"assemblage","tools":["colle","serre-joints"],"description":"Assemblage structure","instructions":"Coller et serrer 24h","estimated_minutes":240},{"phase":"finition","tools":["ponceuse","vernis"],"description":"Ponçage et vernis","instructions":"2 couches vernis","estimated_minutes":180}]'::jsonb, '2026-06-27T16:31:14.150Z', '{}'::jsonb);
INSERT INTO standards (id, name, product_type, steps, created_at, meta) VALUES (2, 'Guides atelier — Fiches fabrication', 'guide', '[{"image":"/fiches/ops/securite.png","phase":"admin","tools":[],"description":"Sécurité — règles non négociables","instructions":"Dégauchisseuse + banc de scie : Mehdi seul. Lunettes + auditive. P100 sablage/finition. Poussoir < 6\". Aspirateur partout sauf ruban capot ouvert.","estimated_minutes":5},{"phase":"admin","tools":[],"description":"Machines assistant vs Mehdi","instructions":"Assistant : ruban, toupie, Domino DF 700, perceuse, sableuses, défonceuse. Mehdi : dégauchisseuse, banc scie, CNC.","estimated_minutes":5},{"image":"/fiches/ops/collage-cernes.png","phase":"assemblage","tools":["Titebond III"],"description":"Guide collage","instructions":"Alterner cernes. 1 serre / 3\". Titebond III : 45 min serrage, 1h manipulation, 24h usinage.","estimated_minutes":10},{"image":"/fiches/ops/timesaver.png","phase":"finition","tools":["Time Saver"],"description":"Guide sablage","instructions":"80→120→180→220. Sens du fil (180+). Marquer au crayon entre grains.","estimated_minutes":10},{"image":"/fiches/ops/domino-etroit.png","phase":"assemblage","tools":["Domino DF 700"],"description":"Domino DF 700","instructions":"Fraises 8–14 mm. Extrémités ÉTROIT, intermédiaires +1/+2. Profondeur = moitié domino.","estimated_minutes":15},{"image":"/fiches/ops/aretes-profiles.png","phase":"finition","tools":[],"description":"Profils arêtes Neya","instructions":"4 profils × tailles 1/8\", 1/4\", 3/8\". Toupie ou râpe + 180.","estimated_minutes":10},{"phase":"finition","tools":[],"description":"Produits finition","instructions":"Osmo LED UV. Saman planches découper. Vernis eau RIVAGE/AZAD/MÕA.","estimated_minutes":10}]'::jsonb, '2026-06-27T17:31:05.719Z', '{"sku":"GUIDE","images":["/fiches/ops/securite.png","/fiches/ops/collage-cernes.png","/fiches/ops/timesaver.png","/fiches/ops/domino-etroit.png"],"source":"Neya_Fiches_Fabrication v1.1 — Mai 2026","version":"1.1"}'::jsonb);
INSERT INTO standards (id, name, product_type, steps, created_at, meta) VALUES (3, 'L3 — Planche à découper', 'L3', '[{"num":1,"image":"/fiches/ops/collage-serres.png","phase":"assemblage","tools":["colle"],"description":"Collage du bloc rayé (1 pour 1)","instructions":"Alterner noyer/érable. Coller à plat, serres alternées. 45 min, gratter colle. Time Saver après 24h.","estimated_minutes":90},{"num":2,"image":"/fiches/ops/l3-l7-vague-etapes.png","phase":"usinage","tools":["gabarit plexi"],"description":"Tracé de la vague — gabarit plexi","instructions":"Bloc à l''envers, ruban double face (4–6). Courbe S. Scie ruban 3/8\".","estimated_minutes":60},{"num":3,"image":"/fiches/ops/l3-l7-vague-etapes.png","phase":"assemblage","tools":[],"description":"Recomposition Noyer ext. / Érable centre","instructions":"Séparer, réassembler motif signature. Recoller 45 min. Recouper 4,5\" × 15\".","estimated_minutes":75},{"image":"/fiches/ops/aretes-profiles.png","phase":"finition","tools":["toupie"],"description":"Cardon des arêtes — profil Neya","instructions":"Cocher le profil : arête vive, chanfrein, 1/4 rond, double chanfrein (1/8\", 1/4\", 3/8\"). Test sur chute obligatoire.","estimated_minutes":30},{"image":"/fiches/ops/timesaver.png","phase":"finition","tools":["Time Saver"],"description":"Sablage","instructions":"Time Saver : ☐ OUI  ☐ NON. Grains : 80 → 120 → 180 → 220. Règle : « si ça passe pas au Time Saver, on fait 80 puis 0 ». 0000 entre couches d''huile seulement.","estimated_minutes":75},{"phase":"finition","tools":["Osmo","vernis"],"description":"Finition","instructions":"Type : Huile / cire alimentaire. 2 couche(s). Usage : contact alimentaire. Vérifier lumière rasante. Étiquette Neya.","estimated_minutes":90}]'::jsonb, '2026-06-27T17:31:05.719Z', '{"sku":"L3","wood":"Noyer (sombre) + Érable (blanc) — 1 pour 1","image":"/fiches/products/L3.png","price":"79,00 $ CAD","finish":"Huile / cire alimentaire — 2 couches","source":"Neya_Fiches_Fabrication v1.1 — Mai 2026","debitage":[{"qty":"3–4","wood":"Noyer","notes":"Sens du fil régulier","piece":"Lattes noyer","dimensions":"4/4\" × ≈1\" × 15\""},{"qty":"3–4","wood":"Érable","notes":"Alterner avec le noyer","piece":"Lattes érable","dimensions":"4/4\" × ≈1\" × 15\""}],"lead_time":"Stock atelier","dimensions":"4,5\" × 15\" — épaisseur 4/4\" (≈19 mm)","finish_coats":"2","finish_usage":"contact alimentaire","debitage_note":null}'::jsonb);
INSERT INTO standards (id, name, product_type, steps, created_at, meta) VALUES (4, 'L7 — Planche à découper suspendue', 'L7', '[{"num":1,"image":"/fiches/ops/l3-l7-vague-etapes.png","phase":"assemblage","tools":[],"description":"Collage, vague, recomposition","instructions":"Bloc 1:1, 4–6 serres, 45 min. Gabarit plexi, ruban 3/8\". Noyer ext., érable centre. Recouper 24\"×24\" losange.","estimated_minutes":120},{"num":2,"image":"/fiches/ops/l7-suspension.png","phase":"usinage","tools":["perceuse"],"description":"Trou de suspension (signature L7)","instructions":"Percer selon gabarit. Vérifier équilibre.","estimated_minutes":30},{"image":"/fiches/ops/aretes-profiles.png","phase":"finition","tools":["toupie"],"description":"Cardon des arêtes — profil Neya","instructions":"Cocher le profil : arête vive, chanfrein, 1/4 rond, double chanfrein (1/8\", 1/4\", 3/8\"). Test sur chute obligatoire.","estimated_minutes":30},{"image":"/fiches/ops/timesaver.png","phase":"finition","tools":["Time Saver"],"description":"Sablage","instructions":"Time Saver : ☐ OUI  ☐ NON. Grains : 80 → 120 → 180 → 220. Règle : « si ça passe pas au Time Saver, on fait 80 puis 0 ». 0000 entre couches d''huile seulement.","estimated_minutes":75},{"phase":"finition","tools":["Osmo","vernis"],"description":"Finition","instructions":"Type : Huile / cire alimentaire. 2 couche(s). Usage : contact alimentaire — suspendue. Vérifier lumière rasante. Étiquette Neya.","estimated_minutes":90}]'::jsonb, '2026-06-27T17:31:05.719Z', '{"sku":"L7","wood":"Noyer + Érable — 1 pour 1","image":"/fiches/products/L7.png","price":"89,00 $ CAD","finish":"Huile / cire alimentaire — 2 couches","source":"Neya_Fiches_Fabrication v1.1 — Mai 2026","related":"L3","debitage":[{"qty":"À calculer","wood":"Noyer","notes":"","piece":"Lattes noyer","dimensions":"4/4\" × ≈1\" × 24\""},{"qty":"À calculer","wood":"Érable","notes":"","piece":"Lattes érable","dimensions":"4/4\" × ≈1\" × 24\""}],"lead_time":"Stock atelier","dimensions":"24\" × 24\" (losange) — 4/4\"","finish_coats":"2","finish_usage":"contact alimentaire — suspendue","debitage_note":"Même principe que la L3 — format plus grand."}'::jsonb);
INSERT INTO standards (id, name, product_type, steps, created_at, meta) VALUES (5, 'MÕA — Tabouret ondulé', 'MÕA', '[{"num":1,"phase":"usinage","tools":["CNC"],"description":"Usinage dessus ondulé","instructions":"Collage lattes puis CNC OU scie ruban + gabarit. Pieds : tour ou CNC.","estimated_minutes":180},{"num":2,"image":"/fiches/ops/domino-placement.png","phase":"assemblage","tools":["Domino DF 700"],"description":"Domino DF 700 — pieds/dessus","instructions":"Documenter fraise, profondeur, hauteur appui, nb dominos.","estimated_minutes":120},{"num":3,"phase":"assemblage","tools":[],"description":"Assemblage final","instructions":"3 pieds + dessus. Aplomb. 4 serres min.","estimated_minutes":60},{"image":"/fiches/ops/aretes-profiles.png","phase":"finition","tools":["toupie"],"description":"Cardon des arêtes — profil Neya","instructions":"Cocher le profil : arête vive, chanfrein, 1/4 rond, double chanfrein (1/8\", 1/4\", 3/8\"). Test sur chute obligatoire.","estimated_minutes":30},{"image":"/fiches/ops/timesaver.png","phase":"finition","tools":["Time Saver"],"description":"Sablage","instructions":"Time Saver : ☐ OUI  ☐ NON. Grains : 80 → 120 → 180 → 220. Règle : « si ça passe pas au Time Saver, on fait 80 puis 0 ». 0000 entre couches d''huile seulement.","estimated_minutes":75},{"phase":"finition","tools":["Osmo","vernis"],"description":"Finition","instructions":"Type : Vernis à l''eau (sans COV). 2-3 couche(s). Usage : assise quotidienne. Vérifier lumière rasante. Étiquette Neya.","estimated_minutes":90}]'::jsonb, '2026-06-27T17:31:05.719Z', '{"sku":"MÕA","wood":"Frêne massif OU noyer massif","image":"/fiches/products/MOA.png","price":"380 $ (frêne) — 420 $ (noyer)","domino":{"note":"Extrémités en ÉTROIT. Intermédiaires +1 ou +2 clics. Espacer 6–8\".","title":"Assemblage Domino — DF 700","fields":["Fraise (Ø)","Profondeur","Hauteur appui","Nb dominos / jonction"],"images":["/fiches/ops/domino-etroit.png","/fiches/ops/domino-plus1.png","/fiches/ops/domino-plus2.png","/fiches/ops/domino-placement.png","/fiches/ops/domino-hauteur.png"],"checklist":["ÉTROIT (0 clic)","+1 CLIC","+2 CLICS"]},"finish":"Vernis à l''eau sans COV","source":"Neya_Fiches_Fabrication v1.1 — Mai 2026","debitage":[{"qty":"1","wood":"Frêne ou noyer","notes":"Découpe scie ruban ou CNC","piece":"Dessus ondulé","dimensions":"Collage lattes — voir plan"},{"qty":"3","wood":"Frêne ou noyer","notes":"Tournés ou CNC","piece":"Pieds","dimensions":"Cylindriques — voir plan"},{"qty":"1","wood":"Noyer (si dessus frêne)","notes":"Inséré avec vague","piece":"Pied signature","dimensions":"Voir plan"}],"lead_time":"1-2 semaines","dimensions":"9,75\" × 15,5\" × 18,75\" (h) — ≈4,2 kg","finish_coats":"2-3","finish_usage":"assise quotidienne","debitage_note":"Tabouret 3 pieds + dessus ondulé. Vague signature sur un pied."}'::jsonb);
